 * @param <InnerType> the type of elements contained in the lists
 */
public class PyListNode<InnerType extends APyObj> extends AIterablePyNode<PyListObj<InnerType>, InnerType> {

    /**
     * The child node that generates elements for the lists.
     */
    private final APyNode<InnerType> child;

