    public PyListNode(APyNode<InnerType> child) {
        this.child = child;
    }

    /**
     * Gets the left child node (element generator).
     *
     * @return the element generator node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.child;
    }

    /**
     * Generates all exhaustive list values based on the exhaustive domain.
     * For each length in the exhaustive domain, generates all combinations
     * of child values for that length.
     *
     * @return a set of all exhaustive lists
     */
    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> result = new HashSet<>();
        Set<InnerType> childVals = this.child.genExVals();
        List<InnerType> childList = new ArrayList<>(childVals);

        // For each length in the exhaustive domain
        for (Integer length : this.exDomain) {
            // Generate all combinations of length len from childList
            generateListCombinations(childList, length, 0, new ArrayList<>(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of elements with a given length.
     *
     * @param elements the elements to choose from
     * @param length the desired length of combinations
     * @param idx the current index
     * @param current the current combination being built
     * @param result the result set to add combinations to
     */
    private void generateListCombinations(List<InnerType> elements, int length, int idx,
                                         List<InnerType> current, Set<PyListObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyListObj<>(new ArrayList<>(current)));
            return;
        }

        if (idx >= elements.size()) {
            idx = 0; // Reset for next position
        }

        // For each element, try adding it to current
        for (InnerType elem : elements) {
            current.add(elem);
            generateListCombinations(elements, length, idx, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates a single random list value based on the random domain.
     *
     * @return a randomly generated list
     */
    @Override
    public PyListObj<InnerType> genRandVal() {
        int lenIdx = random.nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(lenIdx);

        List<InnerType> listVal = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            listVal.add(this.child.genRandVal());
        }

        return new PyListObj<>(listVal);
    }
}

