import main.rice.obj.PyStringObj;
import java.util.*;

/**
 * A node that generates Python string objects.
 * The exhaustive and random domains are lists of lengths.
 * Strings are generated from a fixed set of allowed characters.
 */
public class PyStringNode extends AIterablePyNode<PyStringObj, main.rice.obj.PyCharObj> {

    /**
     * The set of allowed characters for generating strings.
     */
    private final String charset;

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Constructor for a PyStringNode; stores the charset.
     *
     * @param charset the string of allowed characters
     */
    public PyStringNode(String charset) {
        this.charset = charset;
    }

    /**
     * Generates all exhaustive string values based on the exhaustive domain.
     * For each length in the exhaustive domain, generates all combinations
     * of characters for that length.
     *
     * @return a set of all exhaustive strings
     */
    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();

        // For each length in the exhaustive domain
        for (Integer length : this.exDomain) {
            // Generate all strings of this length
            generateStringCombinations(length, 0, new StringBuilder(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of characters with a given length.
     *
     * @param length the desired length
     * @param idx the current index
     * @param current the current string being built
     * @param result the result set to add strings to
     */
    private void generateStringCombinations(int length, int idx, StringBuilder current, Set<PyStringObj> result) {
        if (current.length() == length) {
            result.add(new PyStringObj(current.toString()));
            return;
        }

        // For each character, try adding it to current
        for (int i = 0; i < this.charset.length(); i++) {
            current.append(this.charset.charAt(i));
            generateStringCombinations(length, idx, current, result);
            current.deleteCharAt(current.length() - 1);
        }
    }

    /**
     * Generates a single random string value based on the random domain.
     *
     * @return a randomly generated string
     */
    @Override
    public PyStringObj genRandVal() {
        int lenIdx = random.nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(lenIdx);

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < length; i++) {
            int charIdx = random.nextInt(this.charset.length());
            sb.append(this.charset.charAt(charIdx));
        }

        return new PyStringObj(sb.toString());
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node that generates Python dictionary objects.
 * The exhaustive and random domains are lists of sizes (number of key-value pairs).
 *
 * @param <KeyType> the type of keys in the dictionaries
 * @param <ValType> the type of values in the dictionaries
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends AIterablePyNode<PyDictObj<KeyType, ValType>, APyObj> {

    /**
     * The child node that generates keys.
     */
    private final APyNode<KeyType> keyChild;

    /**
     * The child node that generates values.
     */
    private final APyNode<ValType> valChild;

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Constructor for a PyDictNode; stores the key and value nodes.
     *
     * @param keyChild the node that generates dictionary keys
     * @param valChild the node that generates dictionary values
     */
    public PyDictNode(APyNode<KeyType> keyChild, APyNode<ValType> valChild) {
        this.keyChild = keyChild;
        this.valChild = valChild;
    }

    /**
     * Gets the left child node (key generator).
     *
     * @return the key generator node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.keyChild;
    }

    /**
     * Gets the right child node (value generator).
     *
     * @return the value generator node
     */
    @Override
    public APyNode<?> getRightChild() {
        return this.valChild;
    }

    /**
     * Generates all exhaustive dictionary values based on the exhaustive domain.
     * For each size in the exhaustive domain, generates all combinations
     * of key-value pairs for that size.
     *
     * @return a set of all exhaustive dictionaries
     */
    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
        Set<KeyType> keyVals = this.keyChild.genExVals();
        Set<ValType> valVals = this.valChild.genExVals();
        List<KeyType> keyList = new ArrayList<>(keyVals);
        List<ValType> valList = new ArrayList<>(valVals);

        // Generate all key-value pairs
        List<Map.Entry<KeyType, ValType>> allPairs = new ArrayList<>();
        for (KeyType key : keyList) {
            for (ValType val : valList) {
                allPairs.add(new AbstractMap.SimpleEntry<>(key, val));
            }
        }

        // For each size in the exhaustive domain
        for (Integer size : this.exDomain) {
            // Generate all combinations of size that don't have duplicate keys
            generateDictCombinations(allPairs, keyList, size, 0, new HashMap<>(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of key-value pairs without duplicate keys.
     *
     * @param allPairs all possible key-value pairs
     * @param keyList all possible keys
     * @param size the desired number of pairs
     * @param startIdx the starting index for choosing pairs
     * @param current the current dictionary being built
     * @param result the result set to add dictionaries to
     */
    private void generateDictCombinations(List<Map.Entry<KeyType, ValType>> allPairs,
                                         List<KeyType> keyList, int size, int startIdx,
                                         Map<KeyType, ValType> current,
                                         Set<PyDictObj<KeyType, ValType>> result) {
        if (current.size() == size) {
            result.add(new PyDictObj<>(new HashMap<>(current)));
            return;
        }

        for (int i = startIdx; i < allPairs.size(); i++) {
            Map.Entry<KeyType, ValType> pair = allPairs.get(i);
            // Only add if key is not already in the map
            if (!current.containsKey(pair.getKey())) {
                current.put(pair.getKey(), pair.getValue());
                generateDictCombinations(allPairs, keyList, size, i + 1, current, result);
                current.remove(pair.getKey());
            }
        }
    }

    /**
     * Generates a single random dictionary value based on the random domain.
     *
     * @return a randomly generated dictionary
     */
    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int sizeIdx = random.nextInt(this.ranDomain.size());
        int size = this.ranDomain.get(sizeIdx);

        Map<KeyType, ValType> dictVal = new HashMap<>();
        Set<KeyType> usedKeys = new HashSet<>();

        // Keep generating key-value pairs until we reach the desired size
        int attempts = 0;
        int maxAttempts = size * 100; // Prevent infinite loops
        while (dictVal.size() < size && attempts < maxAttempts) {
            KeyType key = this.keyChild.genRandVal();
            if (!usedKeys.contains(key)) {
                ValType val = this.valChild.genRandVal();
                dictVal.put(key, val);
                usedKeys.add(key);
            }
            attempts++;
        }

        return new PyDictObj<>(dictVal);
    }
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A generator that creates test cases by combining values from multiple argument nodes.
 * It can generate both exhaustive test cases (all combinations) and random test cases.
 */
public class BaseSetGenerator {

    /**
     * The nodes that generate argument values.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random test cases to generate in the combined base set.
     */
    private final int numRand;

    /**
     * Constructor for BaseSetGenerator; stores the nodes and random count.
     *
     * @param nodes the nodes that generate argument values
     * @param numRand the number of random test cases to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases from the nodes.
     * This is the Cartesian product of all exhaustive values from each node.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        Set<TestCase> result = new HashSet<>();

        // Get exhaustive values from each node
        List<Set<APyObj>> allVals = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            allVals.add(new HashSet<>(node.genExVals()));
        }

        // Generate Cartesian product
        generateCartesianProduct(allVals, 0, new ArrayList<>(), result);

        return result;
    }

    /**
     * Helper method to generate the Cartesian product of value sets.
     *
     * @param allVals the list of value sets
     * @param nodeIdx the current node index
     * @param current the current combination being built
     * @param result the result set to add combinations to
     */
    private void generateCartesianProduct(List<Set<APyObj>> allVals, int nodeIdx,
                                         List<APyObj> current, Set<TestCase> result) {
        if (nodeIdx == allVals.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }

        for (APyObj val : allVals.get(nodeIdx)) {
            current.add(val);
            generateCartesianProduct(allVals, nodeIdx + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates a specified number of random test cases from the nodes.
     *
     * @param numTests the number of random test cases to generate
     * @return a list of random test cases
     */
    public List<TestCase> genRandTests(int numTests) {
        List<TestCase> result = new ArrayList<>();

        for (int i = 0; i < numTests; i++) {
            List<APyObj> testArgs = new ArrayList<>();
            for (APyNode<?> node : this.nodes) {
                testArgs.add(node.genRandVal());
            }
            result.add(new TestCase(testArgs));
        }

        return result;
    }

    /**
     * Generates the base set of test cases: all exhaustive tests plus random tests.
     * This combines genExTests() and genRandTests(numRand), removing duplicates.
     *
     * @return a list of all test cases (exhaustive + random)
     */
    public List<TestCase> genBaseSet() {
        // Get all exhaustive tests
        Set<TestCase> exTests = genExTests();
        List<TestCase> result = new ArrayList<>(exTests);

        // Generate random tests, avoiding duplicates
        List<TestCase> randTests = genRandTests(this.numRand * 10); // Generate more to account for overlaps
        for (TestCase test : randTests) {
            if (!exTests.contains(test) && result.size() < exTests.size() + this.numRand) {
                result.add(test);
            }
        }

        return result;
    }

    /**
     * Generates a specified number of random tests and combines with exhaustive tests.
     * Alternative method for generating the base set with a different random count.
     *
     * @param numRand the number of random test cases to generate
     * @return a list of all test cases (exhaustive + random)
     */
    public List<TestCase> genTests(int numRand) {
        // Get all exhaustive tests
        Set<TestCase> exTests = genExTests();
        List<TestCase> result = new ArrayList<>(exTests);

        // Generate random tests, avoiding duplicates
        List<TestCase> randTests = genRandTests(numRand * 10); // Generate more to account for overlaps
        for (TestCase test : randTests) {
            if (!exTests.contains(test) && result.size() < exTests.size() + numRand) {
                result.add(test);
            }
        }

        return result;
    }
}

